
UPDATE courses
SET
  description = 'Курс дает магистрам понимание философии оснований и проблем математики: гносеологические, логические и методологические предпосылки и принципы математики в целом, ее различных направлений и теории. Курс предоставляет возможность ознакомиться с направлениями в философии математики, их историей и методами обоснования.',
  competencies = 'УК-4; УК-5; УК-6; ОПК-1; ОПК-2; ОПК-4',
  learning_outcomes = 'УК-4: владеть навыками академической/профессиональной коммуникации и представления результатов; УК-5: уметь учитывать культурное разнообразие в профессиональной деятельности; УК-6: уметь планировать саморазвитие и профессиональный рост; ОПК-1: уметь решать актуальные задачи прикладной математики и информатики; ОПК-2: уметь совершенствовать и применять современные методы и технологии; ОПК-4: уметь применять ИКТ с учетом требований информационной безопасности (см. индикаторы в УМКД).',
  source = 'История и методология Прикладной математики и информатики УМКД.pdf'
WHERE plan='MatMod' AND index_code='Б1.О.02' AND semester=3;

UPDATE courses
SET
  description = 'Курс дает магистрам понимание философии оснований и современных проблем прикладной математики и информатики: гносеологические, логические и методологические предпосылки математического знания, место математики и информатики в системе знаний. Курс предоставляет возможность ознакомиться с направлениями философии математики, их историей и методами обоснования.',
  competencies = 'УК-3; УК-4; УК-6; ОПК-1; ОПК-2; ОПК-4',
  learning_outcomes = 'УК-3: уметь взаимодействовать и работать в команде; УК-4: владеть навыками академической/профессиональной коммуникации и представления результатов; УК-6: уметь планировать саморазвитие и профессиональный рост; ОПК-1: уметь решать актуальные задачи прикладной математики и информатики; ОПК-2: уметь совершенствовать и применять современные методы и технологии; ОПК-4: уметь применять ИКТ с учетом требований информационной безопасности (см. индикаторы в УМКД).',
  source = 'Современные проблемы прикладной математики и информатики УМКД.pdf'
WHERE plan='MatMod' AND index_code='Б1.О.03' AND semester=3;

UPDATE courses
SET
  description = 'Курс посвящен теории приближений: приближенному представлению одних математических объектов другими (обычно более простой структуры) и оценке отклонения приближающего объекта от приближаемого. Основная часть относится к приближению функций другими, более простыми функциями; рассматриваются вопросы приближений в нормированных пространствах. Теория приближений используется при построении численных алгоритмов решения задач алгебры, анализа и дифференциальных уравнений.',
  competencies = 'УК-1; ПК-1; ПК-12',
  learning_outcomes = 'УК-1: уметь осуществлять критический анализ и синтез информации при решении задач; ПК-1: уметь проводить научные исследования (в т.ч. в составе коллектива) и оформлять результаты; ПК-12: уметь взаимодействовать в проектах/командах и применять ИТ-инструменты в профессиональной деятельности (см. индикаторы в УМКД).',
  source = 'Теория приближений УМКД.pdf'
WHERE plan='MatMod' AND index_code='Б1.О.10' AND semester=3;

UPDATE courses
SET
  description = 'Робот представляет собой управляемую механическую систему со многими степенями свободы, способную совершать сложные движения в пространстве и содержащую один или несколько многозвенных манипуляторов. Для совершенствования конструкции роботов и создания эффективных методов управления требуется изучение кинематики, динамики и современных алгоритмов управления движением механических систем. При построении математических моделей предполагается, что элементы манипулятора могут быть как абсолютно твердыми, так и упругими телами, соединенными идеальными или упругими шарнирами.',
  competencies = 'ОПК-3; ПК-2; ПК-7',
  learning_outcomes = 'ОПК-3: уметь разрабатывать и анализировать математические модели прикладных задач и оценивать их адекватность/точность; ПК-2: уметь разрабатывать концептуальные/теоретические модели для проектной и производственной деятельности; ПК-7: уметь разрабатывать и оценивать проектные решения и планы (см. индикаторы в УМКД).',
  source = 'Математическое моделирование манипуляционных роботов и управление движением  УМКД.pdf'
WHERE plan='MatMod' AND index_code='Б1.О.09' AND semester=2;